import anthropic
import base64
import json
import cv2
from pathlib import Path

client = anthropic.Anthropic()

MODERATION_SCHEMA_TOOL = {
    "name": "video_moderation_result",
    "description": "Structured moderation decision for a video based on sampled frames.",
    "input_schema": {
        "type": "object",
        "properties": {
            "decision": {
                "type": "string",
                "enum": ["allow", "flag_for_review", "auto_reject"],
            },
            "confidence": {"type": "number", "minimum": 0, "maximum": 1},
            "violation_categories": {
                "type": "array",
                "items": {
                    "type": "string",
                    "enum": ["violence", "adult_content", "hate_speech", "spam", "none"],
                },
            },
            "summary": {"type": "string"},
        },
        "required": ["decision", "confidence", "violation_categories", "summary"],
    },
}


def sample_frames_as_b64(video_path: str, n: int = 6) -> list[str]:
    """Sample n evenly-spaced JPEG frames as base64 strings."""
    cap = cv2.VideoCapture(video_path)
    total = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
    indices = [int(i * total / n) for i in range(n)]
    frames = []
    for idx in indices:
        cap.set(cv2.CAP_PROP_POS_FRAMES, idx)
        ret, frame = cap.read()
        if ret:
            _, buf = cv2.imencode(".jpg", frame, [cv2.IMWRITE_JPEG_QUALITY, 85])
            frames.append(base64.standard_b64encode(buf.tobytes()).decode())
    cap.release()
    return frames


def moderate_video(video_path: str) -> dict:
    """Run automated moderation on a video file."""
    frames_b64 = sample_frames_as_b64(video_path, n=6)

    content = []
    for b64 in frames_b64:
        content.append({
            "type": "image",
            "source": {"type": "base64", "media_type": "image/jpeg", "data": b64},
        })
    content.append({
        "type": "text",
        "text": (
            f"These are {len(frames_b64)} evenly-spaced frames from a video submitted to our platform. "
            "Review them for policy violations: violence, adult content, hate speech, or spam. "
            "Return a structured moderation decision."
        ),
    })

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[MODERATION_SCHEMA_TOOL],
        tool_choice={"type": "tool", "name": "video_moderation_result"},
        messages=[{"role": "user", "content": content}],
    )

    tool_block = next(b for b in response.content if b.type == "tool_use")
    return tool_block.input


# Usage
if Path("sample_video.mp4").exists():
    result = moderate_video("sample_video.mp4")
    print(json.dumps(result, indent=2))
